async (params, browser) => {
  // Open WhatsApp Web
  await browser.open('https://web.whatsapp.com')

  // Wait for WhatsApp to load
  await browser.waitForSelector('div[contenteditable=\'true\'][data-tab=\'3\'], div#side', 30000)

  // Let app fully render
  await browser.wait(3000)

  // Search and select contact
  const find_contact = await browser.evaluate(`const searchBox = document.querySelector('div[contenteditable="true"][data-tab="3"]'); if (!searchBox) throw new Error('Search box not found - make sure WhatsApp Web is loaded'); searchBox.focus(); searchBox.textContent = ''; document.execCommand('insertText', false, params.contact_name); searchBox.dispatchEvent(new Event('input', { bubbles: true })); await new Promise(r => setTimeout(r, 2000)); const results = document.querySelectorAll('#pane-side span[title], div[data-testid="cell-frame-title"] span'); let found = false; for (const r of results) { if (r.getAttribute('title')?.toLowerCase().includes(params.contact_name.toLowerCase()) || r.textContent?.toLowerCase().includes(params.contact_name.toLowerCase())) { r.closest('[data-testid="list-item"], [data-testid="cell-frame-container"], div[tabindex]')?.click(); found = true; break; } } if (!found) throw new Error('Contact not found: ' + params.contact_name + ''); await new Promise(r => setTimeout(r, 1500)); return { found: true, contact: params.contact_name }`)

  // Wait for message input
  await browser.waitForSelector('div[contenteditable=\'true\'][data-tab=\'10\'], footer div[contenteditable=\'true\']', 10000)

  // Type and send message
  const result = await browser.evaluate(`const msgBox = document.querySelector('div[contenteditable="true"][data-tab="10"]') || document.querySelector('footer div[contenteditable="true"]'); if (!msgBox) throw new Error('Message input not found'); msgBox.focus(); document.execCommand('insertText', false, params.message); msgBox.dispatchEvent(new Event('input', { bubbles: true })); await new Promise(r => setTimeout(r, 500)); const sendBtn = document.querySelector('span[data-icon="send"], button[aria-label="Send"]'); if (sendBtn) { sendBtn.closest('button')?.click() || sendBtn.click(); } else { msgBox.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter', code: 'Enter', keyCode: 13, which: 13, bubbles: true })); } await new Promise(r => setTimeout(r, 1500)); return { success: true, contact: params.contact_name, message: params.message }`)

  return result
}
